29	// NewValidator creates a new configuration validator
30	func NewValidator() (*ConfigValidator, error) {
31		compiler := jsonschema.NewCompiler()
32	
33		// Load the embedded schema
34		if err := compiler.AddResource("config.schema.json", strings.NewReader(string(schemaJSON))); err != nil {
35			return nil, fmt.Errorf("failed to add schema resource: %w", err)
36		}
37	
38		schema, err := compiler.Compile("config.schema.json")
39		if err != nil {
40			return nil, fmt.Errorf("failed to compile schema: %w", err)
41		}
42	
43		return &ConfigValidator{schema: schema}, nil
44	}
