46	// Validate performs two-phase validation on configuration content
47	func (v *ConfigValidator) Validate(content []byte) error {
48		// Phase 1: YAML syntax validation
49		var rawConfig interface{}
50		if err := yaml.Unmarshal(content, &rawConfig); err != nil {
51			return &ConfigValidationError{
52				Phase:   "syntax",
53				Message: "Invalid YAML syntax",
54				Details: err.Error(),
55				Line:    extractLineNumber(err),
56				Column:  extractColumnNumber(err),
57			}
58		}
59	
60		// Phase 2: Schema validation
61		if err := v.schema.Validate(rawConfig); err != nil {
62			return &ConfigValidationError{
63				Phase:       "schema",
64				Message:     "Configuration does not match schema",
65				Details:     formatSchemaErrors(err),
66				Suggestions: generateSuggestions(err),
67			}
68		}
69	
70		return nil
71	}
