83	// ConfigValidationError represents a configuration validation error
84	type ConfigValidationError struct {
85		Phase       string   // "syntax" or "schema"
86		Message     string   // User-friendly message
87		Line        int      // Line number (syntax errors)
88		Column      int      // Column number (syntax errors)
89		FieldPath   string   // Field path (schema errors)
90		Details     string   // Technical details
91		Suggestions []string // Helpful suggestions
92	}
93	
94	func (e *ConfigValidationError) Error() string {
95		var parts []string
96	
97		parts = append(parts, fmt.Sprintf("[%s] %s", strings.ToUpper(e.Phase), e.Message))
98	
99		if e.Line > 0 {
100			parts = append(parts, fmt.Sprintf("at line %d", e.Line))
101			if e.Column > 0 {
102				parts[len(parts)-1] += fmt.Sprintf(", column %d", e.Column)
103			}
104		}
105	
106		if e.FieldPath != "" {
107			parts = append(parts, fmt.Sprintf("field: %s", e.FieldPath))
108		}
109	
110		result := strings.Join(parts, " ")
111	
112		if e.Details != "" {
113			result += fmt.Sprintf("\n\nDetails: %s", e.Details)
114		}
115	
116		if len(e.Suggestions) > 0 {
117			result += "\n\nSuggestions:"
118			for _, suggestion := range e.Suggestions {
119				result += fmt.Sprintf("\n  - %s", suggestion)
120			}
121		}
122	
123		return result
124	}
