126	// formatSchemaErrors converts JSON schema errors to user-friendly messages
127	func formatSchemaErrors(err error) string {
128		validationErr, ok := err.(*jsonschema.ValidationError)
129		if !ok {
130			return err.Error()
131		}
132	
133		var messages []string
134	
135		// Process all validation errors
136		for _, cause := range flattenErrors(validationErr) {
137			message := formatSingleError(cause)
138			if message != "" {
139				messages = append(messages, message)
140			}
141		}
142	
143		if len(messages) == 0 {
144			return validationErr.Message
145		}
146	
147		return strings.Join(messages, "\n")
148	}
149	
150	// flattenErrors recursively flattens nested validation errors
151	func flattenErrors(err *jsonschema.ValidationError) []*jsonschema.ValidationError {
152		var errors []*jsonschema.ValidationError
153	
154		if len(err.Causes) == 0 {
155			errors = append(errors, err)
156		} else {
157			for _, cause := range err.Causes {
158				errors = append(errors, flattenErrors(cause)...)
159			}
160		}
161	
162		return errors
163	}
