165	// formatSingleError formats a single JSON schema validation error
166	func formatSingleError(err *jsonschema.ValidationError) string {
167		fieldPath := strings.TrimPrefix(err.InstanceLocation, "/")
168		fieldPath = strings.ReplaceAll(fieldPath, "/", ".")
169	
170		message := err.Message
171	
172		// Try to make messages more user-friendly based on common patterns
173		if strings.Contains(message, "missing properties") {
174			missing := extractMissingProperty(message)
175			if missing != "" {
176				if fieldPath == "" {
177					return fmt.Sprintf("missing required field: %s", missing)
178				}
179				return fmt.Sprintf("missing required field: %s.%s", fieldPath, missing)
180			}
181			return fmt.Sprintf("missing required field in %s", fieldPath)
182		}
183	
184		if strings.Contains(message, "expected") && strings.Contains(message, "but got") {
185			expected := extractExpectedType(message)
186			if expected != "" {
187				return fmt.Sprintf("%s: must be %s", fieldPath, expected)
188			}
189			return fmt.Sprintf("%s: invalid type", fieldPath)
190		}
191	
192		if strings.Contains(message, "does not match pattern") && fieldPath == "version" {
193			return "version: must be in format 'X.Y' (e.g., '1.0', '2.1')"
194		}
195	
196		if strings.Contains(message, "does not match pattern") {
197			return fmt.Sprintf("%s: format is invalid", fieldPath)
198		}
199	
200		if strings.Contains(message, "invalid format") {
201			if strings.Contains(message, "uri") {
202				return fmt.Sprintf("%s: must be a valid URL (e.g., 'https://github.com/user/repo')", fieldPath)
203			}
204			if strings.Contains(message, "email") {
205				return fmt.Sprintf("%s: must be a valid email address", fieldPath)
206			}
207			return fmt.Sprintf("%s: invalid format", fieldPath)
208		}
209	
210		if strings.Contains(message, "additional property") {
211			property := extractAdditionalProperty(message)
212			if property != "" {
213				return fmt.Sprintf("unknown field: %s", property)
214			}
215			return "contains unknown fields"
216		}
217	
218		// Default: use original message with field path
219		if fieldPath != "" {
220			return fmt.Sprintf("%s: %s", fieldPath, message)
221		}
222		return message
223	}
