225	// generateSuggestions provides helpful suggestions based on validation errors
226	func generateSuggestions(err error) []string {
227		validationErr, ok := err.(*jsonschema.ValidationError)
228		if !ok {
229			return nil
230		}
231	
232		var suggestions []string
233	
234		for _, cause := range flattenErrors(validationErr) {
235			message := cause.Message
236	
237			if strings.Contains(message, "missing properties") && strings.Contains(message, "version") {
238				suggestions = append(suggestions, "Add 'version: \"1.0\"' to your configuration")
239			}
240	
241			if strings.Contains(message, "does not match pattern") {
242				fieldPath := strings.TrimPrefix(cause.InstanceLocation, "/")
243				if fieldPath == "version" {
244					suggestions = append(suggestions, "Use version format like '1.0' or '2.1' (with quotes)")
245				}
246			}
247	
248			if strings.Contains(message, "invalid format") || strings.Contains(message, "format") {
249				if strings.Contains(message, "uri") {
250					suggestions = append(suggestions, "Ensure URL starts with 'https://' or 'http://'")
251				}
252				if strings.Contains(message, "email") {
253					suggestions = append(suggestions, "Use format like 'user@example.com'")
254				}
255			}
256	
257			if strings.Contains(message, "expected") && strings.Contains(message, "string") {
258				fieldPath := strings.TrimPrefix(cause.InstanceLocation, "/")
259				if fieldPath != "" {
260					suggestions = append(suggestions, fmt.Sprintf("Wrap %s value in quotes", fieldPath))
261				}
262			}
263	
264			if strings.Contains(message, "additional property") {
265				suggestions = append(suggestions, "Check for typos in field names")
266				suggestions = append(suggestions, "See documentation for allowed configuration fields")
267			}
268		}
269	
270		// Remove duplicates
271		seen := make(map[string]bool)
272		var unique []string
273		for _, suggestion := range suggestions {
274			if !seen[suggestion] {
275				seen[suggestion] = true
276				unique = append(unique, suggestion)
277			}
278		}
279	
280		return unique
281	}
