283	// Helper functions for error parsing
284	
285	var lineRegex = regexp.MustCompile(`line (\d+)`)
286	var columnRegex = regexp.MustCompile(`column (\d+)`)
287	
288	func extractLineNumber(err error) int {
289		matches := lineRegex.FindStringSubmatch(err.Error())
290		if len(matches) > 1 {
291			if line, parseErr := strconv.Atoi(matches[1]); parseErr == nil {
292				return line
293			}
294		}
295		return 0
296	}
297	
298	func extractColumnNumber(err error) int {
299		matches := columnRegex.FindStringSubmatch(err.Error())
300		if len(matches) > 1 {
301			if col, parseErr := strconv.Atoi(matches[1]); parseErr == nil {
302				return col
303			}
304		}
305		return 0
306	}
307	
308	func extractMissingProperty(message string) string {
309		// Extract property name from messages like "missing properties: 'version'"
310		re := regexp.MustCompile(`missing properties?: '([^']+)'`)
311		matches := re.FindStringSubmatch(message)
312		if len(matches) > 1 {
313			return matches[1]
314		}
315		return ""
316	}
317	
318	func extractExpectedType(message string) string {
319		// Extract type from messages like "expected string, but got number"
320		re := regexp.MustCompile(`expected (\w+)`)
321		matches := re.FindStringSubmatch(message)
322		if len(matches) > 1 {
323			return "a " + matches[1]
324		}
325		return ""
326	}
327	
328	func extractAdditionalProperty(message string) string {
329		// Extract property name from messages about additional properties
330		re := regexp.MustCompile(`additional property '([^']+)' is not allowed`)
331		matches := re.FindStringSubmatch(message)
332		if len(matches) > 1 {
333			return matches[1]
334		}
335		return ""
336	}
