47	// LoadWithWorkingDir loads configuration from a specific working directory
48	func LoadWithWorkingDir(workingDir string) (*Config, error) {
49		if workingDir == "" {
50			var err error
51			workingDir, err = os.Getwd()
52			if err != nil {
53				return nil, fmt.Errorf("failed to get working directory: %w", err)
54			}
55		}
56	
57		// Use the new ConfigLoader to load from .ddx/config.yaml only
58		loader, err := NewConfigLoaderWithWorkingDir(workingDir)
59		if err != nil {
60			return nil, fmt.Errorf("failed to create config loader: %w", err)
61		}
62	
63		config, err := loader.LoadConfig()
64		if err != nil {
65			// If no config file exists, return default config
66			if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
67				config = DefaultNewConfig()
68			} else {
69				return nil, err
70			}
71		}
72	
73		// Apply defaults to ensure complete configuration
74		config.ApplyDefaults()
75		if config.Agent != nil && config.Agent.Routing != nil &&
76			len(config.Agent.Routing.ProfilePriority) > 0 {
77			fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated; use agent.routing.profile_ladders.default instead")
78		}
79	
80		// Override library path with environment variable if set
81		if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
82			config.Library.Path = envLibraryPath
83		}
84	
85		// Validate the final configuration
86		if err := config.Validate(); err != nil {
87			return nil, fmt.Errorf("configuration validation failed: %w", err)
88		}
89	
90		return config, nil
91	}
