132	// Merge combines this config with another, with the other taking precedence
133	func (c *Config) Merge(other *Config) *Config {
134		result := &Config{
135			Version: c.Version,
136		}
137	
138		// Copy library configuration from base
139		if c.Library != nil {
140			result.Library = &LibraryConfig{
141				Path: c.Library.Path,
142			}
143			if c.Library.Repository != nil {
144				result.Library.Repository = &RepositoryConfig{
145					URL:    c.Library.Repository.URL,
146					Branch: c.Library.Repository.Branch,
147				}
148			}
149		}
150	
151		// Override with other's values
152		if other.Version != "" {
153			result.Version = other.Version
154		}
155		if other.Library != nil {
156			if result.Library == nil {
157				result.Library = &LibraryConfig{}
158			}
159			if other.Library.Path != "" {
160				result.Library.Path = other.Library.Path
161			}
162			if other.Library.Repository != nil {
163				if result.Library.Repository == nil {
164					result.Library.Repository = &RepositoryConfig{}
165				}
166				if other.Library.Repository.URL != "" {
167					result.Library.Repository.URL = other.Library.Repository.URL
168				}
169				if other.Library.Repository.Branch != "" {
170					result.Library.Repository.Branch = other.Library.Repository.Branch
171				}
172			}
173		}
174	
175		return result
176	}
